class Solution:
    def deleteDuplicateFolder(self, paths):
        from collections import defaultdict
        root = {}
        for p in paths:
            cur = root
            for name in p:
                cur = cur.setdefault(name, {})
        sig_count = defaultdict(int)
        def serialize(node):
            if not node:
                return ''
            parts = []
            for name in sorted(node):
                parts.append(name + '(' + serialize(node[name]) + ')')
            s = ''.join(parts)
            sig_count[s] += 1
            return s
        for name in sorted(root):
            serialize(root[name])
        res = []
        def collect(node, path):
            for name in sorted(node):
                child = node[name]
                s = serialize_lookup(child)
                if child and sig_count[s] > 1:
                    continue
                res.append(path + [name])
                collect(child, path + [name])
        def serialize_lookup(node):
            if not node:
                return ''
            parts = []
            for name in sorted(node):
                parts.append(name + '(' + serialize_lookup(node[name]) + ')')
            return ''.join(parts)
        collect(root, [])
        return res

