class Solution:
    def deleteDuplicateFolder(self, paths):
        from collections import defaultdict
        root = {}
        for p in paths:
            cur = root
            for name in p:
                cur = cur.setdefault(name, {})
        count = defaultdict(int)
        memo = {}
        def serialize(node):
            if not node:
                return ''
            parts = []
            for name in sorted(node):
                parts.append(name + '(' + serialize(node[name]) + ')')
            s = ''.join(parts)
            count[s] += 1
            return s
        for name in sorted(root):
            serialize(root[name])
        def sig(node):
            if id(node) in memo:
                return memo[id(node)]
            if not node:
                memo[id(node)] = ''
                return ''
            parts = []
            for name in sorted(node):
                parts.append(name + '(' + sig(node[name]) + ')')
            s = ''.join(parts)
            memo[id(node)] = s
            return s
        res = []
        def walk(node, path):
            for name in sorted(node):
                child = node[name]
                s = sig(child)
                if child and count[s] > 1:
                    continue
                path.append(name)
                res.append(list(path))
                walk(child, path)
                path.pop()
        walk(root, [])
        return res

