var deleteDuplicateFolder = function(paths) {
    const root = new Map();
    for (const p of paths) {
        let cur = root;
        for (const name of p) {
            if (!cur.has(name)) cur.set(name, new Map());
            cur = cur.get(name);
        }
    }
    const count = new Map();
    const serialize = (node) => {
        if (node.size === 0) return '';
        const names = [...node.keys()].sort();
        let parts = '';
        for (const name of names) parts += name + '(' + serialize(node.get(name)) + ')';
        count.set(parts, (count.get(parts) || 0) + 1);
        return parts;
    };
    const names0 = [...root.keys()].sort();
    for (const name of names0) serialize(root.get(name));
    const sigOf = (node) => {
        if (node.size === 0) return '';
        const names = [...node.keys()].sort();
        let parts = '';
        for (const name of names) parts += name + '(' + sigOf(node.get(name)) + ')';
        return parts;
    };
    const res = [];
    const walk = (node, path) => {
        const names = [...node.keys()].sort();
        for (const name of names) {
            const child = node.get(name);
            const s = sigOf(child);
            if (child.size > 0 && (count.get(s) || 0) > 1) continue;
            path.push(name);
            res.push([...path]);
            walk(child, path);
            path.pop();
        }
    };
    walk(root, []);
    return res;
};
